function Sparkline({ data, width = 100, height = 30 }: Props) {
  const max = Math.max(...data);
  const min = Math.min(...data);
  const path = data.map((v, i) => `${i === 0 ? 'M' : 'L'} ${(i / (data.length - 1)) * width} ${height - ((v - min) / (max - min)) * height}`).join(' ');
  return (
    <svg width={width} height={height}>
      <path d={path} stroke="currentColor" fill="none" />
    </svg>
  );
}

